PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "google_id" varchar, "microsoft_id" varchar, "phone" varchar, "company" varchar, "address" text, "country" varchar, "avatar" varchar, "role" varchar not null default 'user');
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" varchar not null, "queue" varchar not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "products" ("id" integer primary key autoincrement not null, "slug" varchar not null, "name" varchar not null, "description" text, "tier" varchar check ("tier" in ('basic', 'pro', 'advanced')) not null default 'basic', "is_active" tinyint(1) not null default '1', "sort_order" integer not null default '0', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "product_prices" ("id" integer primary key autoincrement not null, "product_id" integer not null, "term" varchar not null, "price_inr" integer, "price_usd" integer, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, "billing_cycles" integer, foreign key("product_id") references "products"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "orders" ("id" integer primary key autoincrement not null, "user_id" integer not null, "product_id" integer not null, "term" varchar not null, "currency" varchar not null default 'INR', "amount" integer not null, "gst_amount" integer not null default '0', "total_amount" integer not null, "razorpay_order_id" varchar, "razorpay_payment_id" varchar, "status" varchar check ("status" in ('pending', 'paid', 'failed', 'refunded')) not null default 'pending', "billing_mode" varchar check ("billing_mode" in ('upfront', 'monthly')) not null default 'upfront', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("product_id") references "products"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "subscriptions" ("id" integer primary key autoincrement not null, "user_id" integer not null, "product_id" integer not null, "term" varchar not null, "razorpay_subscription_id" varchar, "razorpay_plan_id" varchar, "status" varchar check ("status" in ('active', 'cancelled', 'expired', 'paused')) not null default 'active', "current_period_start" datetime, "current_period_end" datetime, "amount" integer not null, "currency" varchar not null default 'INR', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("product_id") references "products"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "license_keys" ("id" integer primary key autoincrement not null, "user_id" integer not null, "product_id" integer not null, "order_id" integer, "license_key" varchar not null, "activated_at" datetime, "expires_at" datetime, "is_active" tinyint(1) not null default '1', "activations_count" integer not null default '0', "max_activations" integer not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("product_id") references "products"("id") on delete cascade, foreign key("order_id") references "orders"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "quote_requests" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "company" varchar, "country" varchar not null, "product" varchar, "term" varchar, "seats" varchar, "message" text, "status" varchar check ("status" in ('pending', 'contacted', 'closed')) not null default 'pending', "notes" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "settings" ("id" integer primary key autoincrement not null, "key" varchar not null, "value" text, "type" varchar not null default 'boolean', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "pages" ("id" integer primary key autoincrement not null, "title" varchar not null, "slug" varchar not null, "content" text, "excerpt" text, "meta_title" varchar, "meta_description" text, "featured_image" varchar, "is_published" tinyint(1) not null default '0', "published_at" datetime, "sort_order" integer not null default '0', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "posts" ("id" integer primary key autoincrement not null, "title" varchar not null, "slug" varchar not null, "content" text, "excerpt" text, "meta_title" varchar, "meta_description" text, "featured_image" varchar, "author_name" varchar, "category" varchar, "tags" text, "is_published" tinyint(1) not null default '0', "published_at" datetime, "sort_order" integer not null default '0', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "forms" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "submit_button_text" varchar not null default 'Submit', "success_message" varchar not null default 'Thank you! Your submission has been received.', "redirect_url" varchar, "notification_email" varchar, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "form_fields" ("id" integer primary key autoincrement not null, "form_id" integer not null, "label" varchar not null, "name" varchar not null, "type" varchar not null default 'text', "is_required" tinyint(1) not null default '0', "placeholder" text, "help_text" text, "options" text, "sort_order" integer not null default '0', "width" integer not null default '100', "created_at" datetime, "updated_at" datetime, foreign key("form_id") references "forms"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "form_submissions" ("id" integer primary key autoincrement not null, "form_id" integer not null, "name" varchar, "email" varchar, "data" text not null, "ip_address" varchar, "user_agent" varchar, "is_read" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("form_id") references "forms"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "page_contents" (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            page VARCHAR NOT NULL,
            "key" VARCHAR NOT NULL,
            value TEXT,
            type VARCHAR NOT NULL DEFAULT 'text',
            created_at TIMESTAMP NULL,
            updated_at TIMESTAMP NULL
        );
CREATE TABLE IF NOT EXISTS "media" ("id" integer primary key autoincrement not null, "name" varchar not null, "file_name" varchar not null, "mime_type" varchar not null, "size" integer not null, "disk" varchar not null default 'public', "path" varchar not null, "alt" varchar, "title" varchar, "caption" text, "description" text, "folder" varchar not null default '/', "created_at" datetime, "updated_at" datetime);
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE INDEX "failed_jobs_connection_queue_failed_at_index" on "failed_jobs" ("connection", "queue", "failed_at");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "products_slug_unique" on "products" ("slug");
CREATE UNIQUE INDEX "product_prices_product_id_term_unique" on "product_prices" ("product_id", "term");
CREATE INDEX "orders_razorpay_order_id_index" on "orders" ("razorpay_order_id");
CREATE INDEX "orders_status_index" on "orders" ("status");
CREATE INDEX "subscriptions_razorpay_subscription_id_index" on "subscriptions" ("razorpay_subscription_id");
CREATE INDEX "subscriptions_status_index" on "subscriptions" ("status");
CREATE INDEX "license_keys_license_key_index" on "license_keys" ("license_key");
CREATE UNIQUE INDEX "license_keys_license_key_unique" on "license_keys" ("license_key");
CREATE INDEX "quote_requests_status_index" on "quote_requests" ("status");
CREATE UNIQUE INDEX "settings_key_unique" on "settings" ("key");
CREATE UNIQUE INDEX "pages_slug_unique" on "pages" ("slug");
CREATE UNIQUE INDEX "posts_slug_unique" on "posts" ("slug");
CREATE UNIQUE INDEX "forms_slug_unique" on "forms" ("slug");
CREATE UNIQUE INDEX "page_contents_page_key_unique" on "page_contents" ("page", "key");
CREATE INDEX "page_contents_page_index" on "page_contents" ("page");
CREATE INDEX "media_folder_index" on "media" ("folder");
CREATE INDEX "media_mime_type_index" on "media" ("mime_type");
COMMIT;
