INSERT INTO cache VALUES('autoterra-cache-page_content.about.hero.eyebrow','s:28:"About Infyterra Technologies";',1780300460);
INSERT INTO cache VALUES('autoterra-cache-page_content.about.hero.heading','s:41:"25+ years building software for engineers";',1780300460);
INSERT INTO cache VALUES('autoterra-cache-page_content.about.hero.description','s:253:"AutoTerra is developed by Infyterra Technologies — the engineering software division behind Infycons. Since 1998 we''ve been building tools that help surveyors, road engineers, and geospatial professionals work faster and deliver more accurate results.";',1780300460);
INSERT INTO cache VALUES('autoterra-cache-page_content.about.story.eyebrow','s:9:"Our story";',1780300460);
INSERT INTO cache VALUES('autoterra-cache-page_content.about.story.heading','s:50:"Engineering software built by engineers who use it";',1780300460);
INSERT INTO cache VALUES('autoterra-cache-page_content.about.story.paragraphs','a:3:{i:0;s:280:"Infyterra Technologies was founded by engineers who had experienced the pain of slow, expensive, and inflexible spatial software first-hand. We set out to build tools that respect the way surveyors and engineers actually work — not the way software architects think they should.";i:1;s:319:"Today AutoTerra is deployed by survey firms, road agencies, mapping bureaux, mining companies, and national mapping organisations across 20+ countries. Our clients range from solo practitioners to teams of 200+ seats, and our software processes everything from small site surveys to billion-point aerial LiDAR datasets.";i:2;s:130:"We remain headquartered in Bangalore, India, with regional support offices and certified partners across the geographies we serve.";}',1780300460);
INSERT INTO cache VALUES('autoterra-cache-page_content.about.stats','a:4:{i:0;a:2:{s:6:"number";s:3:"25+";s:5:"label";s:29:"years of engineering software";}i:1;a:2:{s:6:"number";s:3:"20+";s:5:"label";s:18:"countries deployed";}i:2;a:2:{s:6:"number";s:6:"1,000+";s:5:"label";s:26:"engineering firms trust us";}i:3;a:2:{s:6:"number";s:1:"7";s:5:"label";s:16:"product editions";}}',1780300460);
INSERT INTO cache VALUES('autoterra-cache-page_content.about.cta.heading','s:33:"Ready to see AutoTerra in action?";',1780300460);
INSERT INTO cache VALUES('autoterra-cache-page_content.about.cta.description','s:86:"Talk to our team about your workflow and we''ll show you exactly how AutoTerra fits in.";',1780300460);
INSERT INTO cache VALUES('autoterra-cache-page_content.about.cta.button_primary_text','s:14:"Request a demo";',1780300460);
INSERT INTO cache VALUES('autoterra-cache-page_content.about.cta.button_secondary_text','s:16:"Explore products";',1780300460);
INSERT INTO cache VALUES('autoterra-cache-page_content.pricing.hero.eyebrow','s:7:"Pricing";',1780301789);
INSERT INTO cache VALUES('autoterra-cache-page_content.pricing.hero.heading','s:43:"The right edition for every team and budget";',1780301789);
INSERT INTO cache VALUES('autoterra-cache-page_content.pricing.hero.description','s:170:"AutoTerra is priced to make professional-grade LiDAR and survey tools accessible — whether you''re a solo surveyor, a mid-size consultancy, or a national mapping agency.";',1780301789);
INSERT INTO cache VALUES('autoterra-cache-page_content.pricing.hero.region_note','s:143:"Pricing varies by country and region. Contact us for a quote tailored to your location and team size — we''ll respond within one business day.";',1780301789);
INSERT INTO cache VALUES('autoterra-cache-page_content.pricing.faq','a:6:{i:0;a:2:{s:8:"question";s:24:"Why aren''t prices shown?";s:6:"answer";s:262:"AutoTerra is sold in 20+ countries with purchasing power parity applied — the same edition genuinely costs different amounts in different markets. Showing a single price would be misleading. Contact us and we''ll quote your exact region within one business day.";}i:1;a:2:{s:8:"question";s:38:"What''s included in annual maintenance?";s:6:"answer";s:163:"All new feature releases, version upgrades, and priority support are included in the annual maintenance plan. You never pay for a major version upgrade separately.";}i:2;a:2:{s:8:"question";s:26:"What''s a floating license?";s:6:"answer";s:188:"A floating (network) license lets any machine on your network activate the software up to the licensed seat count simultaneously. Ideal for teams where not everyone works at the same time.";}i:3;a:2:{s:8:"question";s:22:"Is there a free trial?";s:6:"answer";s:125:"Yes. We offer a fully featured 30-day trial of AutoTerra Pro Spatial — no credit card required. Apply via the Contact page.";}i:4;a:2:{s:8:"question";s:30:"Do you offer academic pricing?";s:6:"answer";s:140:"Yes. Universities, research institutions, and accredited training organisations are eligible for significantly discounted academic licenses.";}i:5;a:2:{s:8:"question";s:31:"Can I upgrade my edition later?";s:6:"answer";s:165:"Absolutely. You can upgrade to a higher edition at any time — you pay only the difference in license value, and your project files and settings migrate seamlessly.";}}',1780301789);
INSERT INTO cache VALUES('autoterra-cache-page_content.pricing.enterprise.heading','s:32:"Large team or government agency?";',1780301789);
INSERT INTO cache VALUES('autoterra-cache-page_content.pricing.enterprise.description','s:158:"We offer volume discounts, site licenses, and dedicated account management for teams of 10+ seats, government departments, and national mapping organisations.";',1780301789);
