INSERT INTO cache VALUES('autoterra-cache-page_content.home.feature1.features','a:3:{i:0;a:3:{s:4:"icon";s:17:"ti-3d-cube-sphere";s:5:"title";s:28:"LiDAR point cloud processing";s:11:"description";s:117:"GPU-accelerated classification, object detection, vegetation analysis — interactive in full 3D at any dataset size.";}i:1;a:3:{s:4:"icon";s:11:"ti-mountain";s:5:"title";s:27:"Surface & terrain modelling";s:11:"description";s:113:"TIN surfaces, contours, slope analysis, volumes and cross-sections — from raw survey or classified point cloud.";}i:2;a:3:{s:4:"icon";s:18:"ti-vector-triangle";s:5:"title";s:26:"GIS-native CAD environment";s:11:"description";s:109:"Full CAD drafting with live GIS layers, online maps and survey data coexisting in the same project workspace.";}}',1780405739);
