INSERT INTO pages VALUES(1,'About AutoTerra','about-us','<h2>Our Story</h2><p>AutoTerra is developed by Infyterra Technologies — the engineering software division behind Infycons. Since 1998 we&#039;ve been building tools that help surveyors, road engineers, and geospatial professionals work faster.</p><h2>Our Mission</h2><p>Make professional-grade LiDAR and survey tools accessible to every engineering team worldwide.</p>','Learn about AutoTerra and Infyterra Technologies.',NULL,NULL,NULL,1,'2026-05-31 19:35:32',0,'2026-05-31 19:27:44','2026-05-31 19:35:32');
INSERT INTO pages VALUES(2,'Privacy Policy','privacy-policy','<h2>Information We Collect</h2><p>We collect information you provide directly to us, such as when you create an account, purchase a subscription, or contact us for support.</p><h2>How We Use Your Information</h2><p>We use the information we collect to provide, maintain, and improve our services, to process transactions, and to send you technical notices and support messages.</p>',NULL,NULL,NULL,NULL,1,'2026-05-31 19:27:44',0,'2026-05-31 19:27:44','2026-05-31 19:27:44');
INSERT INTO pages VALUES(3,'Terms of Service','terms-of-service','<h2>Acceptance of Terms</h2><p>By accessing or using AutoTerra, you agree to be bound by these Terms of Service.</p><h2>License Grant</h2><p>Subject to these Terms, we grant you a limited, non-exclusive, non-transferable license to use AutoTerra for your internal business purposes.</p>',NULL,NULL,NULL,NULL,1,'2026-05-31 19:27:44',0,'2026-05-31 19:27:44','2026-05-31 19:27:44');
