INSERT INTO posts VALUES(1,'Introducing AutoTerra Pro Spatial','introducing-autoterra-pro-spatial','<h2>The Complete Platform</h2><p>We&#039;re excited to announce AutoTerra Pro Spatial — the most comprehensive geospatial engineering platform we&#039;ve ever built.</p><h2>Key Features</h2><ul><li><p>GPU-accelerated point cloud processing</p></li><li><p>AI classification engine trained on 50M+ labeled points</p></li><li><p>Complete survey and CAD toolkit</p></li><li><p>Corridor and road survey module</p></li></ul>','The most comprehensive geospatial engineering platform — survey + LiDAR + terrain + roads.',NULL,NULL,'http://localhost:8000/storage/media/01KT0Z1GEB4AB6WRY8FHW79BH3.jpeg','AutoTerra Team','Product Updates','["Pro Spatial","LiDAR","Product Launch"]',1,'2026-05-26 00:00:00',0,'2026-05-31 19:27:44','2026-06-01 06:48:40');
INSERT INTO posts VALUES(2,'LiDAR Classification Best Practices','lidar-classification-best-practices','<h2>Getting Accurate Results</h2><p>AI-powered point cloud classification has transformed how we process LiDAR data.</p><h2>Training Data Quality</h2><p>The classification engine works best when you provide high-quality training data. Even 500 well-labeled points can significantly improve accuracy.</p>','Tips and techniques for getting the most accurate classification results.',NULL,NULL,NULL,'LiDAR Team','Tutorials','["LiDAR","Classification"]',1,'2026-05-19 19:35:32',0,'2026-05-31 19:27:44','2026-05-31 19:35:32');
INSERT INTO posts VALUES(3,'Highway Corridor Survey Workflow','highway-corridor-survey-workflow','<h2>From Mobile LiDAR to Deliverable</h2><p>Highway corridor surveys using mobile LiDAR have become the standard for road agencies worldwide.</p><h2>Step 1: Data Import</h2><p>Import mobile LiDAR data directly — LAS, LAZ, E57 supported.</p><h2>Step 2: Classification</h2><p>Use AI to automatically separate ground, vegetation, buildings, vehicles.</p>','How to streamline your highway corridor survey workflow.',NULL,NULL,NULL,'Solutions Team','Case Studies','["Highways","Mobile LiDAR"]',1,'2026-05-11 19:35:32',0,'2026-05-31 19:27:44','2026-05-31 19:35:32');
