INSERT INTO page_contents VALUES(15,'home','feature1.features','[{"icon":"ti-3d-cube-sphere" ,"title":"LiDAR point cloud processing","description":"GPU-accelerated classification, object detection, vegetation analysis \u2014 interactive in full 3D at any dataset size."},{"icon":"ti-mountain" ,"title":"Surface & terrain modelling","description":"TIN surfaces, contours, slope analysis, volumes and cross-sections \u2014 from raw survey or classified point cloud."},{"icon":"ti-vector-triangle","title":"GIS-native CAD environment","description":"Full CAD drafting with live GIS layers, online maps and survey data coexisting in the same project workspace."}]','json','2026-05-31 12:36:31','2026-06-01 10:05:30');
