INSERT INTO page_contents VALUES(21,'home','testimonials','[{"quote":"AutoTerra has become an integral part of every infrastructure project we handle. One platform replacing five separate tools \u2014 the productivity gain is significant.","author_name":"Project Director","author_org":"Infrastructure Consultancy \u2014 India","author_img":"http://localhost:8000/storage/media/01KT3TPSG5WMH6T60CKXVRKREG.png"},{"quote":"Point cloud classification accuracy is competitive with specialist platforms costing three times as much. Pro Spatial is exceptional value for serious LiDAR work.","author_name":"LiDAR Processing Lead","author_org":"Geospatial Survey Company \u2014 UAE","author_img":"http://localhost:8000/storage/media/01KT3TPSG5WMH6T60CKXVRKREG.png"}, {"quote":"Point cloud classification accuracy is competitive with specialist platforms costing three times as much. Pro Spatial is exceptional value for serious LiDAR work.","author_name":"LiDAR Processing Lead","author_org":"Geospatial Survey Company \u2014 UAE","author_img":"http://localhost:8000/storage/media/01KT3TPSG5WMH6T60CKXVRKREG.png"}, {"quote":"Point cloud classification accuracy is competitive with specialist platforms costing three times as much. Pro Spatial is exceptional value for serious LiDAR work.","author_name":"LiDAR Processing Lead","author_org":"Geospatial Survey Company \u2014 UAE","author_img":"http://localhost:8000/storage/media/01KT3TPSG5WMH6T60CKXVRKREG.png"}]','json','2026-05-31 12:36:31','2026-06-02 11:02:55');
