INSERT INTO page_contents VALUES(29,'about','hero.eyebrow','About Infyterra Technologies','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(30,'about','hero.heading','25+ years building software for engineers','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(31,'about','hero.description','AutoTerra is developed by Infyterra Technologies — the engineering software division behind Infycons. Since 1998 we''ve been building tools that help surveyors, road engineers, and geospatial professionals work faster and deliver more accurate results.','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(32,'about','story.eyebrow','Our story','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(33,'about','story.heading','Engineering software built by engineers who use it','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(34,'about','story.paragraphs','["Infyterra Technologies was founded by engineers who had experienced the pain of slow, expensive, and inflexible spatial software first-hand. We set out to build tools that respect the way surveyors and engineers actually work \u2014 not the way software architects think they should.","Today AutoTerra is deployed by survey firms, road agencies, mapping bureaux, mining companies, and national mapping organisations across 20+ countries. Our clients range from solo practitioners to teams of 200+ seats, and our software processes everything from small site surveys to billion-point aerial LiDAR datasets.","We remain headquartered in Bangalore, India, with regional support offices and certified partners across the geographies we serve."]','json','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(35,'about','timeline','[{"year":"1998","text":"Infyterra Technologies founded in Bangalore. First survey data processing tool released for AutoCAD-based workflows."},{"year":"2004","text":"AutoPlotter becomes the reference tool for land surveying across India. 500+ engineering firms adopt the platform."},{"year":"2010","text":"GIS+ module released. Infycons international expansion begins \u2014 first clients in UAE, Kenya, and Southeast Asia."},{"year":"2016","text":"AutoRoads launched for complete highway geometric design. First national mapping agency deployment."},{"year":"2020","text":"AutoTerra brand launched \u2014 unified suite covering the full survey to LiDAR to terrain to CAD pipeline."},{"year":"2024","text":"AI-powered point cloud classification engine released. Pro Spatial becomes the flagship edition."},{"year":"Today","text":"AutoTerra deployed in 20+ countries. 7 editions. AutoRoads early access programme open. UAV Photogrammetry module in development."}]','json','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(36,'about','stats','[{"number":"25+","label":"years of engineering software"},{"number":"20+","label":"countries deployed"},{"number":"1,000+","label":"engineering firms trust us"},{"number":"7","label":"product editions"}]','json','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(37,'about','values.eyebrow','Our values','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(38,'about','values.heading','What drives us','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(39,'about','values.description','Every decision we make traces back to one goal: make the engineer''s job faster, more accurate, and less frustrating.','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(40,'about','values.cards','[{"title":"Engineering accuracy first","description":"Every algorithm, interpolation method, and output format is reviewed by practising civil engineers before release."},{"title":"Built for the field, not just the office","description":"Our tools are designed around real workflows \u2014 the way surveyors actually work in the field and the office."},{"title":"Global reach, local support","description":"We serve 20+ countries with localised support, regional pricing, and technical documentation in multiple languages."},{"title":"Continuous improvement","description":"Annual maintenance plans include every new feature release \u2014 not just bug fixes. Your software gets better every year."},{"title":"Honest, transparent licensing","description":"No hidden fees, no mandatory cloud, no annual re-licensing traps. You own your licence term."},{"title":"Open to the future","description":"Python scripting API, REST endpoints, and plugin SDK mean AutoTerra grows with your workflow."}]','json','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(41,'about','team.eyebrow','The team','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(42,'about','team.heading','The people behind AutoTerra','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(43,'about','team.description','A dedicated team of civil engineers, geospatial scientists, and software developers — all based in Bangalore.','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(44,'about','team.members','[{"name":"Sandipan Chakraborty","role":"Director & Founder"},{"name":"Engineering Lead","role":"Head of Engineering"},{"name":"LiDAR Lead","role":"LiDAR & Geospatial Science"},{"name":"Solutions Lead","role":"Customer Solutions"}]','json','2026-05-31 12:36:31','2026-05-31 12:36:31');
