INSERT INTO page_contents VALUES(47,'about','clients.description','Government agencies, highway consultants, survey firms, mining companies, and mapping bureaux across Asia, Africa, and the Middle East.','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(48,'about','infycons.eyebrow','The Infycons family','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(49,'about','infycons.heading','Part of a 25-year engineering software legacy','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(50,'about','infycons.paragraphs','["AutoTerra is the international brand built on the same codebase and engineering expertise as Infycons. Our Indian market products \u2014 AutoPlotter, Road Estimator, and AutoRoads \u2014 have been trusted by L&T, Tata, JSW, IndianOil, Reliance, and hundreds of government departments across India for over two decades.","Infycons products have been trusted by L&T, Tata, JSW, IndianOil, Reliance, and hundreds of government departments across India for over two decades."]','json','2026-05-31 12:36:31','2026-05-31 12:36:31');
