INSERT INTO page_contents VALUES(62,'products','hero.description','From individual site surveys to billion-point aerial LiDAR datasets and full highway corridor projects. Choose the edition that fits your workflow.','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(63,'products','tracks.eyebrow','Two tracks','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(64,'products','tracks.heading','Find your workflow','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(65,'products','tracks.description','AutoTerra is organised into two product tracks — choose based on your primary discipline. Both tracks share the same CAD engine and project format.','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(66,'products','tracks','[{"name":"Survey \/ CAD \/ Terrain","subtitle":"Traditional surveying through to corridor design","description":"For field engineers, surveyors and CAD operators who work with total station data, GPS, DTM surfaces, contours, cross-sections and volumes. Full CAD environment included."},{"name":"LiDAR \/ Point Cloud","subtitle":"Site-scale to corridor-scale airborne & UAV data","description":"For LiDAR operators, UAV survey teams and geospatial analysts who need GPU-accelerated point cloud classification, object detection, DSM\/DEM export and large-dataset handling."}]','json','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(67,'products','comparison.heading','Feature comparison','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(68,'products','comparison.description','All editions include the core CAD environment, DWG/DXF exchange and online map integration.','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(69,'products','faq','[{"question":"Can I upgrade between editions?","answer":"Yes \u2014 upgrades are available at any time. You pay the difference between your current licence and the target edition. Your project files, settings and code libraries carry across without any migration step."},{"question":"What is the difference between AutoTerra Spatial and Pro Spatial?","answer":"AutoTerra Spatial bundles Standard-level survey and terrain tools with basic LiDAR processing \u2014 suited for site-scale projects with standard point cloud capacity. Pro Spatial adds the full LiDAR suite: large-dataset tile-based processing, all 8 object detection categories, 3D animation export, and advanced classification routines."},{"question":"Is a perpetual licence available, or subscription only?","answer":"Both perpetual and annual subscription licences are available. Pricing varies by region \u2014 contact the team for a quote tailored to your location."},{"question":"What are the system requirements?","answer":"AutoTerra runs on Windows 10 \/ 11 (64-bit). Minimum 8 GB RAM; 16 GB recommended for LiDAR work. A dedicated GPU is recommended for point cloud processing and 3D terrain views \u2014 especially for Pro Spatial with large datasets."}]','json','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(70,'products','cta.heading','Ready to see AutoTerra in action?','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(71,'products','cta.description','Request a 30-day trial of Pro Spatial — full platform, no restrictions.','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(72,'products','cta.button_primary_text','Buy Now','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(73,'products','cta.button_secondary_text','Talk to sales','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(74,'pricing','hero.eyebrow','Pricing','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(75,'pricing','hero.heading','The right edition for every team and budget','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(76,'pricing','hero.description','AutoTerra is priced to make professional-grade LiDAR and survey tools accessible — whether you''re a solo surveyor, a mid-size consultancy, or a national mapping agency.','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(77,'pricing','hero.region_note','Pricing varies by country and region. Contact us for a quote tailored to your location and team size — we''ll respond within one business day.','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(78,'pricing','track_description.survey','4 editions in the Survey / CAD / Terrain track — from free viewing to the complete survey + LiDAR platform.','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(79,'pricing','track_description.lidar','3 editions in the LiDAR / Point Cloud track — focused on classification, terrain, and large-scale airborne or drone-LiDAR workflows.','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(80,'pricing','faq','[{"question":"Why aren''t prices shown?","answer":"AutoTerra is sold in 20+ countries with purchasing power parity applied \u2014 the same edition genuinely costs different amounts in different markets. Showing a single price would be misleading. Contact us and we''ll quote your exact region within one business day."},{"question":"What''s included in annual maintenance?","answer":"All new feature releases, version upgrades, and priority support are included in the annual maintenance plan. You never pay for a major version upgrade separately."},{"question":"What''s a floating license?","answer":"A floating (network) license lets any machine on your network activate the software up to the licensed seat count simultaneously. Ideal for teams where not everyone works at the same time."},{"question":"Is there a free trial?","answer":"Yes. We offer a fully featured 30-day trial of AutoTerra Pro Spatial \u2014 no credit card required. Apply via the Contact page."},{"question":"Do you offer academic pricing?","answer":"Yes. Universities, research institutions, and accredited training organisations are eligible for significantly discounted academic licenses."},{"question":"Can I upgrade my edition later?","answer":"Absolutely. You can upgrade to a higher edition at any time \u2014 you pay only the difference in license value, and your project files and settings migrate seamlessly."}]','json','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(81,'pricing','enterprise.heading','Large team or government agency?','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(82,'pricing','enterprise.description','We offer volume discounts, site licenses, and dedicated account management for teams of 10+ seats, government departments, and national mapping organisations.','text','2026-05-31 12:36:31','2026-05-31 12:36:31');
