INSERT INTO page_contents VALUES(134,'pro_spatial','stats','[{"number":"50+","label":"LiDAR file formats"},{"number":"1 B+","label":"points processed per session"},{"number":"10","label":"integrated modules"},{"number":"20+","label":"countries deployed"},{"number":"GPU","label":"accelerated classification"}]','json','2026-05-31 12:36:31','2026-05-31 12:36:31');
INSERT INTO page_contents VALUES(135,'pro_spatial','modules','[{"eyebrow":"Point Cloud Processing","heading":"Handle any LiDAR dataset \u2014 at any scale","description":"AutoTerra Pro Spatial ingests raw point cloud data from airborne, mobile, terrestrial, and drone-borne sensors.","chips":["LAS \/ LAZ 1.0-1.4","E57","PLY \/ XYZ \/ PTS","FLS \/ FWS","RCP \/ RCS","COPC streaming"]},{"eyebrow":"AI-Powered Classification","heading":"Deep learning classification \u2014 trained on 50M+ labeled points","description":"The built-in classification engine uses convolutional neural networks pre-trained on a global labeled dataset.","chips":["Ground \/ Low veg.","Buildings","High vegetation","Powerlines","Vehicles","Bridge decks","Water surface","Custom classes"]},{"eyebrow":"Terrain & DTM Generation","heading":"Survey-grade terrain models from classified cloud to raster","description":"Derive bare-earth DTMs, surface models (DSM), and normalized height models (nDHM) from classified point cloud data.","chips":["DTM \/ DSM \/ nDHM","TIN interpolation","Break-line enforcement","Contour generation","Slope \/ Aspect","Flood modeling","GeoTIFF export"]},{"eyebrow":"Survey & CAD Integration","heading":"From 3D point cloud to submission-ready CAD drawings","description":"Pro Spatial bridges the gap between raw spatial data and engineering deliverables.","chips":["DXF \/ DWG read & write","Cross-sections","Long-profiles","Control points","Stake-out","Field data import"]},{"eyebrow":"Corridors & Road Survey","heading":"Road asset inventory and alignment design from LiDAR","description":"The corridor module automates road asset extraction from mobile or airborne LiDAR.","chips":["Asset inventory","Lane marking detection","Sign recognition","Pavement analysis","Alignment design","IRI calculation"]},{"eyebrow":"Coming Soon","heading":"UAV Photogrammetry \u2014 from raw images to survey-grade point cloud","description":"The UAV Photogrammetry add-on brings drone imagery processing directly into your AutoTerra workflow.","chips":["Dense matching","Bundle adjustment","Orthoimage export","GCP integration","DSM generation","Accuracy reporting"]}]','json','2026-05-31 12:36:31','2026-05-31 12:36:31');
