INSERT INTO page_contents VALUES(233,'cms:testing-page','sec-html',unistr('<div class="feat-grid">\u000a      <div>\u000a        <div class="sec-eye">Platform capabilities</div>\u000a        <h2 class="sec-h2">One licence. One interface.<br>Zero software-switching.</h2>\u000a        <p style="font-size:14px;color:#5A7A96;line-height:1.7;margin-bottom:28px;">\u000a          From classifying a billion-point cloud to generating finished CAD plans and\u000a          engineering reports — inside a single session, without exporting to another application.\u000a        </p>\u000a        <div class="feat-list">\u000a          <div class="feat-item">\u000a            <div class="feat-icon blue"><i class="ti ti-3d-cube-sphere" style="font-size:20px;"></i></div>\u000a            <div>\u000a              <h4>LiDAR point cloud processing</h4>\u000a              <p>GPU-accelerated classification, object detection, vegetation analysis — interactive in full 3D at any dataset size.</p>\u000a            </div>\u000a          </div>\u000a          <div class="feat-item">\u000a            <div class="feat-icon blue"><i class="ti ti-mountain" style="font-size:20px;"></i></div>\u000a            <div>\u000a              <h4>Surface &amp; terrain modelling</h4>\u000a              <p>TIN surfaces, contours, slope analysis, volumes and cross-sections — from raw survey or classified point cloud.</p>\u000a            </div>\u000a          </div>\u000a          <div class="feat-item">\u000a            <div class="feat-icon blue"><i class="ti ti-vector-triangle" style="font-size:20px;"></i></div>\u000a            <div>\u000a              <h4>GIS-native CAD environment</h4>\u000a              <p>Full CAD drafting with live GIS layers, online maps and survey data coexisting in the same project workspace.</p>\u000a            </div>\u000a          </div>\u000a        </div>\u000a        <a href="pro-spatial.html" style="display:inline-flex;align-items:center;gap:6px;color:#00A8F8;font-size:14px;font-weight:700;margin-top:24px;">\u000a          Explore all modules <i class="ti ti-arrow-right" style="font-size:14px;"></i>\u000a        </a>\u000a      </div>\u000a\u000a      <!-- DEVELOPER: Replace with AutoTerra Pro Spatial screenshot -->\u000a      <div class="ph" style="height:360px;">\u000a        <i class="ti ti-screenshot"></i>\u000a        <span class="ph-t">AutoTerra Pro Spatial — point cloud classification view</span>\u000a        <span class="ph-d">Software screenshot · 800×500px</span>\u000a        <span class="ph-d">Dark UI showing GPU-rendered coloured point cloud in 3D viewport</span>\u000a      </div>\u000a    </div>'),'html_section:section-light','2026-06-01 06:26:29','2026-06-01 06:26:29');
